  9	// ── Particle Canvas (same as OraviniLanding) ─────────────────────────────────
 10	function ParticleCanvas() {
 11	  const ref = useRef<HTMLCanvasElement>(null);
 12	  const mouseRef = useRef({ x: -9999, y: -9999 });
 13	  const activeRef = useRef(false);
 14	
 15	  useEffect(() => {
 16	    const canvas = ref.current!;
 17	    const ctx = canvas.getContext("2d")!;
 18	    let raf: number;
 19	
 20	    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
 21	    resize();
 22	    window.addEventListener("resize", resize);
 23	
 24	    const N = 90;
 25	    const CONNECT_DIST = 150;
 26	    const CURSOR_PULL_DIST = 160;
 27	    const CURSOR_PUSH_DIST = 55;
 28	
 29	    type P = { x: number; y: number; vx: number; vy: number; r: number; o: number };
 30	    const ps: P[] = Array.from({ length: N }, () => ({
 31	      x: Math.random() * canvas.width, y: Math.random() * canvas.height,
 32	      vx: (Math.random() - 0.5) * 0.3, vy: (Math.random() - 0.5) * 0.3,
 33	      r: Math.random() * 1.6 + 0.4, o: Math.random() * 0.45 + 0.12,
 34	    }));
 35	
 36	    const onMouse = (e: MouseEvent) => { mouseRef.current = { x: e.clientX, y: e.clientY }; activeRef.current = true; };
 37	    window.addEventListener("mousemove", onMouse);
 38	
 39	    const draw = () => {
 40	      ctx.clearRect(0, 0, canvas.width, canvas.height);
 41	      const mx = mouseRef.current.x, my = mouseRef.current.y;
 42	      const active = activeRef.current;
 43	
 44	      ps.forEach(p => {
 45	        if (active) {
 46	          const dx = p.x - mx, dy = p.y - my;
 47	          const dist = Math.sqrt(dx * dx + dy * dy);
 48	          if (dist < CURSOR_PUSH_DIST && dist > 0) {
 49	            const force = (CURSOR_PUSH_DIST - dist) / CURSOR_PUSH_DIST;
 50	            p.vx += (dx / dist) * force * 0.6; p.vy += (dy / dist) * force * 0.6;
 51	          } else if (dist < CURSOR_PULL_DIST && dist > 0) {
 52	            const pull = (1 - dist / CURSOR_PULL_DIST) * 0.018;
 53	            p.vx -= (dx / dist) * pull; p.vy -= (dy / dist) * pull;
 54	          }
 55	        }
 56	        p.vx *= 0.97; p.vy *= 0.97;
 57	        p.x += p.vx; p.y += p.vy;
 58	        if (p.x < 0) p.x = canvas.width; if (p.x > canvas.width) p.x = 0;
 59	        if (p.y < 0) p.y = canvas.height; if (p.y > canvas.height) p.y = 0;
 60	        ctx.beginPath(); ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
 61	        ctx.fillStyle = `rgba(212,180,97,${p.o})`; ctx.fill();
 62	      });
 63	
 64	      for (let i = 0; i < ps.length; i++) {
 65	        for (let j = i + 1; j < ps.length; j++) {
 66	          const dx = ps[i].x - ps[j].x, dy = ps[i].y - ps[j].y;
 67	          const d = Math.sqrt(dx * dx + dy * dy);
 68	          if (d < CONNECT_DIST) {
 69	            const alpha = 0.22 * (1 - d / CONNECT_DIST);
 70	            ctx.beginPath(); ctx.moveTo(ps[i].x, ps[i].y); ctx.lineTo(ps[j].x, ps[j].y);
 71	            ctx.strokeStyle = `rgba(212,180,97,${alpha})`; ctx.lineWidth = 0.6; ctx.stroke();
 72	          }
 73	        }
 74	      }
 75	
 76	      if (active) {
 77	        ps.forEach(p => {
 78	          const dx = p.x - mx, dy = p.y - my;
 79	          const d = Math.sqrt(dx * dx + dy * dy);
 80	          if (d < CURSOR_PULL_DIST) {
 81	            const alpha = 0.3 * (1 - d / CURSOR_PULL_DIST);
 82	            ctx.beginPath(); ctx.moveTo(p.x, p.y); ctx.lineTo(mx, my);
 83	            ctx.strokeStyle = `rgba(212,180,97,${alpha})`; ctx.lineWidth = 0.4; ctx.stroke();
 84	          }
 85	        });
 86	      }
 87	
 88	      raf = requestAnimationFrame(draw);
 89	    };
 90	    draw();
 91	    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", resize); window.removeEventListener("mousemove", onMouse); };
 92	  }, []);
 93	
 94	  return <canvas ref={ref} style={{ position: "absolute", inset: 0, zIndex: 0, display: "block" }} />;
 95	}
