 97	// ── Scroll Animate ────────────────────────────────────────────────────────────
 98	function useScrollAnim() {
 99	  useEffect(() => {
100	    const els = document.querySelectorAll("[data-anim]");
101	    const obs = new IntersectionObserver(entries => {
102	      entries.forEach(e => {
103	        if (e.isIntersecting) {
104	          (e.target as HTMLElement).style.opacity = "1";
105	          (e.target as HTMLElement).style.transform = "none";
106	        }
107	      });
108	    }, { threshold: 0.1 });
109	    els.forEach(el => obs.observe(el));
110	    return () => obs.disconnect();
111	  }, []);
112	}
113	
114	function Anim({ children, delay = 0, from = "translateY(40px)", style = {} }: { children: React.ReactNode; delay?: number; from?: string; style?: React.CSSProperties }) {
115	  return (
116	    <div data-anim="1" style={{ opacity: 0, transform: from, transition: `opacity 0.8s ease ${delay}ms, transform 0.8s ease ${delay}ms`, ...style }}>
117	      {children}
118	    </div>
119	  );
120	}
121	
122	// ── Counter ───────────────────────────────────────────────────────────────────
123	function Counter({ to, suffix = "", prefix = "" }: { to: number; suffix?: string; prefix?: string }) {
124	  const [val, setVal] = useState(0);
125	  const ref = useRef<HTMLSpanElement>(null);
126	  const started = useRef(false);
127	  useEffect(() => {
128	    const obs = new IntersectionObserver(([e]) => {
129	      if (e.isIntersecting && !started.current) {
130	        started.current = true;
131	        const dur = 1800, start = Date.now();
132	        const tick = () => {
133	          const p = Math.min((Date.now() - start) / dur, 1);
134	          setVal(Math.round(p * to));
135	          if (p < 1) requestAnimationFrame(tick);
136	        };
137	        tick();
138	      }
139	    }, { threshold: 0.5 });
140	    if (ref.current) obs.observe(ref.current);
141	    return () => obs.disconnect();
142	  }, [to]);
143	  return <span ref={ref}>{prefix}{val}{suffix}</span>;
144	}
