146	// ── 3D Tilt Card ──────────────────────────────────────────────────────────────
147	function TiltCard({ children, style = {} }: { children: React.ReactNode; style?: React.CSSProperties }) {
148	  const ref = useRef<HTMLDivElement>(null);
149	  const onMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
150	    const el = ref.current!;
151	    const r = el.getBoundingClientRect();
152	    const x = (e.clientX - r.left) / r.width - 0.5;
153	    const y = (e.clientY - r.top) / r.height - 0.5;
154	    el.style.transform = `perspective(600px) rotateY(${x * 14}deg) rotateX(${-y * 14}deg) scale(1.03)`;
155	  }, []);
156	  const onLeave = useCallback(() => { if (ref.current) ref.current.style.transform = "perspective(600px) rotateY(0) rotateX(0) scale(1)"; }, []);
157	  return (
158	    <div ref={ref} onMouseMove={onMove} onMouseLeave={onLeave} style={{ transition: "transform 0.2s ease", transformStyle: "preserve-3d", ...style }}>
159	      {children}
160	    </div>
161	  );
162	}
