165	function ProgressBarPreview({ style: barStyle }: { style: string }) {
166	  const [pct, setPct] = useState(0);
167	  const animRef = useRef<number | null>(null);
168	  const startRef = useRef(0);
169	
170	  const getDuration = (s: string) => {
171	    if (s === "slow-start") return 6000;
172	    if (s === "fast-start") return 3000;
173	    return 4500;
174	  };
175	
176	  const getEase = (s: string, t: number) => {
177	    if (s === "slow-start") return Math.pow(t, 2.5);
178	    if (s === "fast-start") return 1 - Math.pow(1 - t, 2.5);
179	    return t;
180	  };
181	
182	  useEffect(() => {
183	    setPct(0);
184	    if (animRef.current) cancelAnimationFrame(animRef.current);
185	    startRef.current = Date.now();
186	    const dur = getDuration(barStyle);
187	    const tick = () => {
188	      const elapsed = Date.now() - startRef.current;
189	      const t = Math.min(elapsed / dur, 1);
190	      setPct(Math.round(getEase(barStyle, t) * 100));
191	      if (t < 1) animRef.current = requestAnimationFrame(tick);
192	      else {
193	        setTimeout(() => {
194	          setPct(0);
195	          startRef.current = Date.now();
196	          animRef.current = requestAnimationFrame(tick);
197	        }, 1200);
198	      }
199	    };
200	    animRef.current = requestAnimationFrame(tick);
201	    return () => { if (animRef.current) cancelAnimationFrame(animRef.current); };
202	  }, [barStyle]);
203	
204	  return (
205	    <div style={{ width: "100%", height: 6, background: "rgba(255,255,255,0.08)", borderRadius: 99, overflow: "hidden", marginTop: 10 }}>
206	      <div style={{ width: `${pct}%`, height: "100%", background: `linear-gradient(90deg, ${GOLD}, ${GOLD_BRIGHT})`, borderRadius: 99, transition: "width 0.1s linear", boxShadow: `0 0 8px ${GOLD}66` }} />
