513	  });
514	
515	  const categories = ["General", "Training", "Masterclass", "Product Demo", "Tutorial", "Webinar Replay"];
516	  const totalViews = (videos as any[]).reduce((s: number, v: any) => s + (v.views || 0), 0);
517	
518	  return (
519	    <div className="space-y-6">
520	      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
