523	        <StatCard icon={Globe} label="Public" value={(videos as any[]).filter((v: any) => v.isPublic).length} color="#34d399" />
524	        <StatCard icon={Film} label="Categories" value={new Set((videos as any[]).map((v: any) => v.category)).size} color="#a78bfa" />
525	      </div>
