529	        <Button size="sm" style={{ background: GOLD, color: "#000" }} className="font-semibold gap-1.5" onClick={() => setShowCreate(true)}>
530	          <Plus className="w-4 h-4" /> Add Video
531	        </Button>
532	      </div>
533	
534	      {isLoading ? (
535	        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
536	          {[1, 2, 3].map((i) => <Skeleton key={i} className="h-48 rounded-xl bg-zinc-800" />)}
537	        </div>
538	      ) : videos.length === 0 ? (
539	        <EmptyState
540	          icon={Video}
541	          title="No videos yet"
542	          desc="Add your video links to host them in your video library."
543	          action={
544	            <Button size="sm" style={{ background: GOLD, color: "#000" }} onClick={() => setShowCreate(true)}>
545	              <Plus className="w-4 h-4 mr-1.5" /> Add Video
546	            </Button>
547	          }
548	        />
549	      ) : (
550	        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
551	          {(videos as any[]).map((v: any) => (
552	            <Card key={v.id} className="bg-zinc-900/60 border-zinc-800 hover:border-zinc-700 transition-all overflow-hidden group">
553	              <div
554	                className="h-36 flex items-center justify-center relative"
555	                style={{
556	                  background: v.thumbnailUrl
557	                    ? `url(${v.thumbnailUrl}) center/cover no-repeat`
558	                    : `linear-gradient(135deg, ${GOLD}10, rgba(18,14,30,0.6))`,
559	                }}
560	              >
561	                {!v.thumbnailUrl && (
562	                  <Film className="w-10 h-10" style={{ color: `${GOLD}50` }} />
563	                )}
564	                {v.category && (
565	                  <Badge className="absolute top-2 right-2 text-[10px]" style={{ background: `${GOLD}22`, color: GOLD, border: "none" }}>
566	                    {v.category}
567	                  </Badge>
568	                )}
569	                {v.isPublic && (
570	                  <Badge className="absolute top-2 left-2 text-[10px] bg-green-500/20 text-green-400 border-none">
571	                    Public
572	                  </Badge>
573	                )}
574	              </div>
575	              <CardContent className="p-4">
576	                <h4 className="font-bold text-white text-sm line-clamp-1 mb-1">{v.title}</h4>
577	                {v.description && (
578	                  <p className="text-xs text-zinc-500 line-clamp-2 mb-2">{v.description}</p>
579	                )}
580	                <div className="flex items-center justify-between">
581	                  <div className="flex items-center gap-3 text-xs text-zinc-500">
582	                    <span className="flex items-center gap-1"><Eye className="w-3 h-3" /> {v.views || 0}</span>
583	                    {v.duration && <span className="flex items-center gap-1"><Clock className="w-3 h-3" /> {v.duration}m</span>}
584	                  </div>
585	                  <div className="flex items-center gap-1">
586	                    {v.videoUrl && (
587	                      <Button variant="ghost" size="icon" className="h-7 w-7 text-zinc-400 hover:text-white" asChild>
588	                        <a href={v.videoUrl} target="_blank" rel="noreferrer">
589	                          <ExternalLink className="w-3.5 h-3.5" />
590	                        </a>
591	                      </Button>
592	                    )}
593	                    <Button
594	                      variant="ghost"
595	                      size="icon"
596	                      className="h-7 w-7 text-zinc-500 hover:text-red-400"
597	                      onClick={() => deleteMut.mutate(v.id)}
598	                    >
599	                      <Trash2 className="w-3.5 h-3.5" />
600	                    </Button>
601	                  </div>
602	                </div>
603	              </CardContent>
604	            </Card>
605	          ))}
606	        </div>
607	      )}
608	
609	      <Dialog open={showCreate} onOpenChange={setShowCreate}>
610	        <DialogContent className="bg-zinc-900 border-zinc-700 max-w-lg max-h-[90vh] overflow-y-auto">
611	          <DialogHeader>
612	            <DialogTitle className="text-white font-bold">Add Video</DialogTitle>
613	          </DialogHeader>
614	          <div className="space-y-4 py-2">
615	            <div>
616	              <label className="text-xs text-zinc-400 mb-1.5 block">Title *</label>
617	              <Input
618	                placeholder="Video title"
619	                value={form.title}
620	                onChange={(e) => setForm({ ...form, title: e.target.value })}
621	                className="bg-zinc-800 border-zinc-700 text-white"
622	              />
623	            </div

